                'username' => $username,
                'token' => $token,
                'reset' => 'true'
            ], UrlGeneratorInterface::ABSOLUTE_URL);

            try {
                $event = new LostPasswordEvent($user, $loginUrl);
                $this->get('event_dispatcher')->dispatch(AdminEvents::LOGIN_LOSTPASSWORD, $event);

                // only send mail if it wasn't prevented in event
